import nltk
from string import punctuation
import seaborn as sns
import matplotlib.pyplot as plt

# Constants
PUNCTUATION = set(punctuation)

def task_func(text):
    words = nltk.word_tokenize(text)
    has_words = False
    word_freq = {}

    for word in words:
        if word[0] == '$' and word not in PUNCTUATION and len(word) > 1:
            if word in word_freq:
                word_freq[word] += 1
            else:
                word_freq[word] = 1
            has_words = True

    if has_words:
        plt.figure(figsize=(8,6))
        sns.barplot(x=list(word_freq.keys()), y=list(word_freq.values()))
        plt.title('Frequency of words starting with "$" character')
        plt.xlabel('Words')
        plt.ylabel('Frequency')
        plot = plt.gca()
    else:
        plot = None

    return tuple(plot, has_words)
